// Version A: mutating the domain object during setup
class UserA {
  name = '';
  email = '';
  isAdmin = false;
  setName(n: string) { this.name = n; return this; }
  setEmail(e: string) { this.email = e; return this; }
  setAdmin(a: boolean) { this.isAdmin = a; return this; }
}
const a = new UserA().setName('Amy').setEmail('a@x');

// Version B: separate assembler that builds an immutable domain object
class UserB {
  constructor(readonly name: string, readonly email: string, readonly isAdmin: boolean) {}
}
class UserBuilderB {
  private data = {name: '', email: '', isAdmin: false};
  name(n: string) { this.data.name = n; return this; }
  email(e: string) { this.data.email = e; return this; }
  admin(a: boolean) { this.data.isAdmin = a; return this; }
  build() { /* validate here */ return new UserB(this.data.name, this.data.email, this.data.isAdmin); }
}
const b = new UserBuilderB().name('Amy').email('a@x').build();
